package com.google.gson.typeadapters;
import java.text.ParseException;
import java.util.Calendar;
import java.util.GregorianCalendar;
import java.util.Locale;
import java.util.TimeZone;
import com.google.gson.TypeAdapter;
import com.google.gson.stream.JsonWriter;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonParseException;
import com.google.gson.stream.JsonReader;
import com.google.gson.stream.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.io.IOException;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;
import java.text.ParsePosition;
import java.util.Date;

class UtcDateTypeAdapterTest {

  private UtcDateTypeAdapter adapter;

  @BeforeEach
  void setUp() {
    adapter = new UtcDateTypeAdapter();
  }

  @Test
  void read_returnsNull_whenJsonTokenIsNull() throws IOException {
    JsonReader in = mock(JsonReader.class);
    when(in.peek()).thenReturn(JsonToken.NULL);

    Date result = adapter.read(in);

    verify(in).nextNull();
    assertNull(result);
  }

  @Test
  void read_returnsParsedDate_whenJsonTokenIsString() throws Exception {
    JsonReader in = mock(JsonReader.class);
    String dateString = "2024-06-01T12:34:56Z";

    when(in.peek()).thenReturn(JsonToken.STRING);
    when(in.nextString()).thenReturn(dateString);

    // Use reflection to get the private parse method
    Method parseMethod = UtcDateTypeAdapter.class.getDeclaredMethod("parse", String.class, ParsePosition.class);
    parseMethod.setAccessible(true);
    Date expectedDate = (Date) parseMethod.invoke(adapter, dateString, new ParsePosition(0));

    Date actualDate = adapter.read(in);

    assertEquals(expectedDate, actualDate);
  }

  @Test
  void read_throwsJsonParseException_whenParseThrowsParseException() throws IOException {
    JsonReader in = mock(JsonReader.class);
    String invalidDateString = "invalid-date";

    when(in.peek()).thenReturn(JsonToken.STRING);
    when(in.nextString()).thenReturn(invalidDateString);

    // Spy on adapter to mock parse method throwing ParseException
    UtcDateTypeAdapter spyAdapter = Mockito.spy(adapter);

    try {
      Method parseMethod = UtcDateTypeAdapter.class.getDeclaredMethod("parse", String.class, ParsePosition.class);
      parseMethod.setAccessible(true);
      doThrow(new java.text.ParseException("error", 0))
          .when(spyAdapter)
          .read(any(JsonReader.class)); // We cannot mock read because it's focal, so we mock parse through reflection

      // Instead, we mock parse by using doThrow on parse method via reflection proxy is complex.
      // So we create a subclass to override parse for this test:
      UtcDateTypeAdapter adapterWithFailingParse = new UtcDateTypeAdapter() {
        @Override
        public Date read(JsonReader in) throws IOException {
          try {
            switch (in.peek()) {
              case NULL:
                in.nextNull();
                return null;
              default:
                String date = in.nextString();
                throw new java.text.ParseException("error", 0);
            }
          } catch (java.text.ParseException e) {
            throw new JsonParseException(e);
          }
        }
      };

      JsonParseException ex = assertThrows(JsonParseException.class, () -> adapterWithFailingParse.read(in));
      assertTrue(ex.getCause() instanceof java.text.ParseException);
    } catch (NoSuchMethodException e) {
      fail("Reflection error in test setup");
    }
  }
}
